import requests

BASE_URL = "http://localhost:4000"
TIMEOUT = 30

def test_admin_login_with_valid_credentials():
    url = f"{BASE_URL}/api/auth/admin-login"
    payload = {
        "email": "admin@fmb.com",
        "password": "AdminPassword#2026"
    }
    headers = {
        "Content-Type": "application/json"
    }
    try:
        response = requests.post(url, json=payload, headers=headers, timeout=TIMEOUT)
        response.raise_for_status()
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    json_response = response.json()
    assert "token" in json_response, "Token not found in response"
    token = json_response["token"]
    assert isinstance(token, str) and len(token) > 0, "Invalid token received"

test_admin_login_with_valid_credentials()

import requests

def test_adminloginwithinvalidcredentials():
    base_url = "http://localhost:4000"
    url = f"{base_url}/api/auth/admin-login"
    invalid_payload = {
        "email": "admin@fmb.com",
        "password": "WrongPassword#2026"
    }
    headers = {
        "Content-Type": "application/json"
    }
    try:
        response = requests.post(url, json=invalid_payload, headers=headers, timeout=30)
        assert response.status_code == 401 or response.status_code == 400, \
            f"Expected 401 or 400 Unauthorized/Bad Request but got {response.status_code}"
        json_response = response.json()
        assert "token" not in json_response, "Token should not be present in response on failed login"
        assert "error" in json_response or "message" in json_response, "Error message should be present in the response"
        error_msg = json_response.get("error") or json_response.get("message")
        assert isinstance(error_msg, str) and len(error_msg) > 0, "Error message should be a non-empty string"
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

test_adminloginwithinvalidcredentials()

import requests

def test_fetch_available_branches():
    base_url = "http://localhost:4000"
    url = f"{base_url}/api/auth/branches"
    headers = {
        "Accept": "application/json"
    }
    try:
        response = requests.get(url, headers=headers, timeout=30)
        response.raise_for_status()
    except requests.exceptions.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 200, f"Expected status code 200 but got {response.status_code}"

    try:
        response_json = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    assert isinstance(response_json, dict), "Response JSON is not a dictionary/object"

    assert "branches" in response_json, "Response JSON does not contain 'branches' key"

    branches = response_json["branches"]

    assert isinstance(branches, list), "'branches' is not a list"

    # Validate branch objects if available in the list
    if branches:
        branch = branches[0]
        assert isinstance(branch, dict), "Branch item is not a dictionary"
        # Check for expected branch fields: 'id' and 'name'
        expected_keys = {"id", "name"}
        missing_keys = expected_keys - branch.keys()
        assert not missing_keys, f"Missing expected keys in branch item: {missing_keys}"

test_fetch_available_branches()
